// src/pages/AdminArticles.js
import React, { useState, useEffect, useRef } from 'react';
import { useAuth } from '../context/AuthContext';
import { api } from '../utils/api';
import '../components/UI.css';
import './AdminArticles.css';

// SheetJS loaded via CDN script tag in index.html (or via npm)
// We'll use dynamic import since it's in package.json
let XLSX;

const DEPT_LABELS = { laadpalen: 'Laadpalen', zonnepanelen: 'Zonnepanelen', all: 'Alle afdelingen', algemeen: 'Algemeen' };

export default function AdminArticles() {
  const { token } = useAuth();
  const [articles, setArticles] = useState([]);
  const [loading, setLoading] = useState(true);
  const [importing, setImporting] = useState(false);
  const [importMode, setImportMode] = useState('merge');
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [search, setSearch] = useState('');
  const fileRef = useRef();

  const load = () =>
    api.getArticles(token).then(d => setArticles(d.articles)).finally(() => setLoading(false));

  useEffect(() => { load(); }, [token]);

  const filtered = articles.filter(a =>
    !search || a.name.toLowerCase().includes(search.toLowerCase()) || a.internalRef.toLowerCase().includes(search.toLowerCase())
  );

  const handleImport = async (e) => {
    const file = e.target.files[0];
    if (!file) return;
    setImporting(true); setError(''); setSuccess('');

    try {
      if (!XLSX) XLSX = await import('xlsx');
      const data = await file.arrayBuffer();
      const wb = XLSX.read(data, { type: 'array' });
      const ws = wb.Sheets[wb.SheetNames[0]];
      const rows = XLSX.utils.sheet_to_json(ws);

      if (rows.length === 0) throw new Error('Geen rijen gevonden in het Excel-bestand.');

      const result = await api.importArticles(token, rows, importMode);
      setSuccess(`${result.count} artikelen ${importMode === 'replace' ? 'vervangen' : 'samengevoegd'}.`);
      await load();
    } catch (err) {
      setError(err.message || 'Importfout.');
    } finally {
      setImporting(false);
      e.target.value = '';
    }
  };

  const downloadTemplate = async () => {
    if (!XLSX) XLSX = await import('xlsx');
    const template = [
      { odooId: 101, internalRef: 'BEV-001', name: 'Schroef M6x20', unit: 'stuk', departments: 'all', category: 'bevestiging' },
      { odooId: 201, internalRef: 'LP-001', name: 'Laadkabel Type 2', unit: 'stuk', departments: 'laadpalen', category: 'bekabeling' },
      { odooId: 301, internalRef: 'ZP-001', name: 'Zonnepaneel 400W', unit: 'stuk', departments: 'zonnepanelen', category: 'panelen' },
    ];
    const ws = XLSX.utils.json_to_sheet(template);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, 'Artikelen');
    XLSX.writeFile(wb, 'artikelen_template.xlsx');
  };

  if (loading) return <div style={{ display: 'flex', justifyContent: 'center', padding: 60 }}><span className="spinner" style={{ width: 28, height: 28 }} /></div>;

  return (
    <div className="fade-in">
      {/* Import panel */}
      <div className="card import-card">
        <div className="import-header">
          <div>
            <div className="import-title">Excel importeren</div>
            <div className="import-sub">Kolommen: odooId, internalRef, name, unit, departments, category</div>
          </div>
          <button className="btn btn-ghost btn-sm" onClick={downloadTemplate}>⬇ Sjabloon downloaden</button>
        </div>

        {error && <div className="alert alert-error" style={{ marginTop: 12 }}><span>⚠</span> {error}</div>}
        {success && <div className="alert alert-success" style={{ marginTop: 12 }}><span>✓</span> {success}</div>}

        <div className="import-controls">
          <select className="form-input form-select" style={{ width: 220 }} value={importMode} onChange={e => setImportMode(e.target.value)}>
            <option value="merge">Samenvoegen (toevoegen/bijwerken)</option>
            <option value="replace">Alles vervangen</option>
          </select>
          <input type="file" accept=".xlsx,.xls" ref={fileRef} onChange={handleImport} style={{ display: 'none' }} />
          <button className="btn btn-primary btn-sm" onClick={() => fileRef.current.click()} disabled={importing}>
            {importing ? <><span className="spinner" style={{ width: 14, height: 14 }} /> Importeren...</> : '📂 Bestand kiezen'}
          </button>
        </div>

        <div className="import-hint">
          <strong>departments</strong>: gebruik kommagescheiden waarden: <code>laadpalen</code>, <code>zonnepanelen</code>, <code>all</code> (voor alle afdelingen)
        </div>
      </div>

      {/* Article list */}
      <div style={{ display: 'flex', alignItems: 'center', gap: 16, margin: '20px 0 12px' }}>
        <input type="text" className="form-input" style={{ maxWidth: 300 }}
          placeholder="Zoek artikel..." value={search} onChange={e => setSearch(e.target.value)} />
        <span style={{ fontSize: 13, color: 'var(--text3)' }}>{filtered.length} van {articles.length}</span>
      </div>

      <div className="card" style={{ padding: 0, overflow: 'hidden' }}>
        <table className="table">
          <thead>
            <tr><th>Ref</th><th>Naam</th><th>Eenheid</th><th>Categorie</th><th>Afdeling(en)</th><th>Odoo ID</th></tr>
          </thead>
          <tbody>
            {filtered.map(a => (
              <tr key={a.id}>
                <td style={{ fontFamily: 'var(--font-display)', fontSize: 12, color: 'var(--text3)' }}>{a.internalRef}</td>
                <td style={{ color: 'var(--text)', fontWeight: 500 }}>{a.name}</td>
                <td>{a.unit}</td>
                <td style={{ fontSize: 12 }}>{a.category}</td>
                <td>
                  <div style={{ display: 'flex', gap: 4, flexWrap: 'wrap' }}>
                    {a.departments.map(d => (
                      <span key={d} className={`badge badge-dept-${d}`} style={{ fontSize: 10 }}>
                        {DEPT_LABELS[d] || d}
                      </span>
                    ))}
                  </div>
                </td>
                <td style={{ fontFamily: 'var(--font-display)', fontSize: 12, color: 'var(--text3)' }}>{a.odooId}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}
